#include <bits/stdc++.h>
using namespace std;
int n,m,a[100005],b[100005];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++)
        scanf("%d",&b[i]);
    sort(a+1,a+n+1);
    long long ans=0;
    for(int i=1;i<=m;i++){
        if(a[1]>b[i])
            ans+=a[1]-b[i];
        else if(a[n]<b[i])
            ans+=b[i]-a[n];
        else{
            int l=1,r=n;
            while(l<r){
                int mid=(l+r)>>1;
                if(a[mid]>=b[i])
                    r=mid;
                else
                    l=mid+1;
            }
            //printf("%d\n",l);
            ans+=min(abs(a[l]-b[i]),abs(b[i]-a[l-1]));
        }
    }
    printf("%lld",ans);
    return 0;
}
